import argparse
import json
import pickle
from pathlib import Path
from collections import defaultdict
import numpy as np
import heapq
import glob
from cogniplan_env import ExplorationEnv

def load_model(checkpoint_dir):
    checkpoint_dir = Path(checkpoint_dir)
    model_path = checkpoint_dir / "model.pkl"
    if model_path.exists():
        with open(model_path, "rb") as f:
            return pickle.load(f)
    return {"type": "heuristic_utility_over_dist", "alpha": 2.5, "beta": 1.3}

def get_env_type(map_path):
    pstr = str(map_path).lower()
    if 'room' in pstr: return 'room'
    if 'tunnel' in pstr: return 'tunnel'
    if 'outdoor' in pstr: return 'outdoor'
    return 'room'

def select_waypoint(obs, model):
    neighbors = obs.get("neighbors", [])
    if not neighbors:
        return None
    nodes = obs.get("nodes", [])
    if not nodes:
        return neighbors[0] if neighbors else None

    def coord_to_tuple(c):
        if isinstance(c, np.ndarray):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        if isinstance(c, (list, tuple)):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        return c

    node_dict = {}
    for node in nodes:
        coords = coord_to_tuple(node.get("coords"))
        if coords is not None:
            node_dict[coords] = node

    current_pos = coord_to_tuple(obs.get("robot_pos", np.array([0.0, 0.0])))
    if current_pos not in node_dict:
        min_d = float('inf')
        closest = None
        for nc in node_dict:
            d = ((nc[0] - current_pos[0]) ** 2 + (nc[1] - current_pos[1]) ** 2 ) ** 0.5
            if d < min_d:
                min_d = d
                closest = nc
        if closest is not None:
            current_pos = closest

    if current_pos not in node_dict:
        best_utility = -1.0
        best_target = neighbors[0]
        for n in neighbors:
            nc = coord_to_tuple(n)
            u = node_dict.get(nc, {}).get("utility", 0.0) if nc in node_dict else 0.0
            if u > best_utility:
                best_utility = u
                best_target = n
        return best_target

    graph = {}
    utilities = {}
    visited_flags = {}
    for coord, node in node_dict.items():
        neighs = [coord_to_tuple(n) for n in node.get("neighbors", [])]
        graph[coord] = [n for n in neighs if n in node_dict]
        utilities[coord] = float(node.get("utility", 0.0))
        visited_flags[coord] = bool(node.get("visited", False))

    def get_edge_distance(a, b):
        return ((a[0] - b[0]) ** 2 + (a[1] - b[1]) ** 2 ) ** 0.5

    def shortest_path_distance(start, goal):
        if start == goal:
            return 0.0
        pq = [(0.0, start)]
        dists = {start: 0.0}
        while pq:
            d, curr = heapq.heappop(pq)
            if d > dists.get(curr, float('inf')):
                continue
            if curr == goal:
                return d
            for neigh in graph.get(curr, []):
                edge_d = get_edge_distance(curr, neigh)
                new_d = d + edge_d
                if new_d < dists.get(neigh, float('inf')):
                    dists[neigh] = new_d
                    heapq.heappush(pq, (new_d, neigh))
        return float('inf')

    def find_next_on_path(start, goal):
        if start == goal:
            return start
        pq = [(0.0, start)]
        dists = {start: 0.0}
        prev = {start: None}
        while pq:
            d, curr = heapq.heappop(pq)
            if d > dists.get(curr, float('inf')):
                continue
            if curr == goal:
                break
            for neigh in graph.get(curr, []):
                edge_d = get_edge_distance(curr, neigh)
                new_d = d + edge_d
                if new_d < dists.get(neigh, float('inf')):
                    dists[neigh] = new_d
                    prev[neigh] = curr
                    heapq.heappush(pq, (new_d, neigh))
        if goal not in prev or prev[goal] is None:
            return None
        curr = goal
        while prev.get(curr) is not None and prev.get(curr) != start:
            curr = prev[curr]
        return curr

    alpha = model.get("alpha", 2.0)
    beta = model.get("beta", 1.0)
    best_score = -float('inf')
    best_target = None
    for tcoord in utilities:
        util = utilities[tcoord]
        if util <= 0.0 or visited_flags.get(tcoord, True):
            continue
        dist = shortest_path_distance(current_pos, tcoord)
        if dist == float('inf') or dist <= 0.01:
            continue
        score = (util ** beta) / (dist ** alpha + 1.0)
        if score > best_score:
            best_score = score
            best_target = tcoord

    if best_target is None:
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        if best_n is not None:
            return best_n
        return neighbors[0] if neighbors else None

    next_coord = find_next_on_path(current_pos, best_target)
    if next_coord is None or next_coord == current_pos:
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        if best_n is not None:
            return best_n
        return neighbors[0] if neighbors else None

    for neigh_raw in neighbors:
        if coord_to_tuple(neigh_raw) == next_coord:
            return neigh_raw
    return next_coord

def run_evaluation(data_path, checkpoint, output_path, is_local_test=True):
    model = load_model(checkpoint)
    data_path = Path(data_path)
    output_path = Path(output_path)
    output_path.parent.mkdir(parents=True, exist_ok=True)
    maps = []
    config_path = data_path / "eval_config.json"
    if config_path.exists():
        try:
            with open(config_path, "r") as f:
                config = json.load(f)
            if isinstance(config, dict) and "maps" in config:
                for m in config.get("maps", []):
                    full_path = data_path / m if isinstance(m, str) and not Path(m).is_absolute() else Path(m)
                    if full_path.exists() or str(full_path).startswith(str(data_path)):
                        maps.append(full_path)
            elif isinstance(config, list):
                for m in config:
                    full_path = data_path / m if isinstance(m, str) else Path(m)
                    maps.append(full_path)
        except Exception as e:
            print("Error loading eval_config.json:", str(e))
    if not maps:
        print("No eval_config.json or empty, using 3 training maps per type for local testing.")
        for env_type in ["room", "tunnel", "outdoor"]:
            patterns = [
                str(data_path / "maps_train" / env_type / "*.png"),
                str(data_path / "maps_eval" / env_type / "*.png"),
                str(data_path / env_type / "**/*.png"),
            ]
            found = []
            for pat in patterns:
                found.extend(glob.glob(pat, recursive=True))
            found = sorted(set(found))[:3]
            maps.extend([Path(f) for f in found])
    if not maps:
        print("No maps found via primary methods, using recursive glob.")
        found = glob.glob(str(data_path / "**/*.png"), recursive=True)
        maps = [Path(f) for f in sorted(found)[:9]]
    if not maps:
        raise RuntimeError("No maps could be located in data_path")
    print(f"Evaluating on {len(maps)} maps.")
    per_episode = []
    per_type = defaultdict(lambda: {"explored_rate": [], "travel_distance": [], "success": []})
    total_explored = 0.0
    successful_distances = []
    n_episodes = len(maps)
    for map_path_p in maps:
        map_path = str(map_path_p)
        env_type = get_env_type(map_path)
        try:
            env = ExplorationEnv(map_path=map_path)
            obs = env.reset()
            done = False
            step_count = 0
            while not done and step_count < 128:
                target = select_waypoint(obs, model)
                if target is None:
                    break
                if isinstance(target, (tuple, list, np.ndarray)):
                    target = (float(target[0]), float(target[1]))
                obs, info = env.step(target)
                done = info.get("done", False)
                step_count += 1
            metrics = env.get_metrics()
            success = 1 if metrics.get("success", metrics.get("explored_rate", 0.0) > 0.9999) else 0
            explored_rate = metrics.get("explored_rate", 0.0)
            travel_distance = metrics.get("travel_distance", 0.0)
            per_episode.append({
                "map_path": map_path,
                "env_type": env_type,
                "success": success,
                "travel_distance": float(travel_distance),
                "explored_rate": float(explored_rate)
            })
            per_type[env_type]["explored_rate"].append(explored_rate)
            per_type[env_type]["success"].append(success)
            if success:
                per_type[env_type]["travel_distance"].append(travel_distance)
                successful_distances.append(travel_distance)
            total_explored += explored_rate
        except Exception as e:
            print(f"Error on map {map_path}: {str(e)}")
            per_episode.append({
                "map_path": map_path,
                "env_type": env_type,
                "success": 0,
                "travel_distance": 0.0,
                "explored_rate": 0.0
            })
            per_type[env_type]["explored_rate"].append(0.0)
            per_type[env_type]["success"].append(0)
    explored_rate_mean = total_explored / n_episodes if n_episodes > 0 else 0.0
    success_rate = sum(ep["success"] for ep in per_episode) / n_episodes if n_episodes > 0 else 0.0
    travel_distance_mean = np.mean(successful_distances) if successful_distances else 0.0
    per_type_summary = {}
    for t, stats in per_type.items():
        n = len(stats["success"]) or 1
        s_rate = sum(stats["success"]) / n
        e_rate = np.mean(stats["explored_rate"])
        d_list = stats.get("travel_distance", [])
        d_mean = np.mean(d_list) if d_list else 0.0
        per_type_summary[t] = {
            "explored_rate": float(e_rate),
            "travel_distance": float(d_mean),
            "success_rate": float(s_rate)
        }
    if successful_distances:
        score_terms = [300.0 / d for d in successful_distances]
        exploration_score = np.mean(score_terms)
    else:
        exploration_score = 0.0
    results = {
        "explored_rate": float(explored_rate_mean),
        "travel_distance": float(travel_distance_mean),
        "success_rate": float(success_rate),
        "per_episode": per_episode,
        "per_type": per_type_summary,
        "total_episodes": int(n_episodes),
        "exploration_score": float(exploration_score)
    }
    with open(output_path, "w") as f:
        json.dump(results, f, indent=2)
    print("Evaluation completed with exploration_score proxy based on success and distance.")
    print(f"Success rate: {success_rate:.4f}, Explored: {explored_rate_mean:.4f}, Avg dist: {travel_distance_mean:.2f}")
    print(f"Proxy exploration_score: {exploration_score:.4f}")
    print("Local test on train subset done." if is_local_test else "Full evaluation done.")
    return results

if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, default="/data")
    parser.add_argument("--checkpoint", type=str, default="checkpoints/baseline")
    parser.add_argument("--output", type=str, default="output.json")
    args = parser.parse_args()
    run_evaluation(args.data_path, args.checkpoint, args.output)
